package com.mabarcu.backend.controllers;
import com.mabarcu.backend.services.AppService;
import org.springframework.web.bind.annotation.*;
import java.util.*;
@RestController @RequestMapping("/api/social") public class SocialController { private final AppService service; public SocialController(AppService service){this.service=service;} @GetMapping("/{userId}/friends") public List<String> friends(@PathVariable int userId){return service.getFriends(userId);} @GetMapping("/{userId}/requests") public List<String> requests(@PathVariable int userId){return service.getRequests(userId);} @GetMapping("/{userId}/blocked") public List<String> blocked(@PathVariable int userId){return service.getBlocked(userId);} @PostMapping("/{userId}/friends") public void addFriend(@PathVariable int userId,@RequestBody Map<String,String> b){service.addFriend(userId,b.get("name"),b.getOrDefault("status","Online"),b.getOrDefault("game","Mobile Legends"));} @DeleteMapping("/{userId}/friends") public void remove(@PathVariable int userId,@RequestParam String label){service.removeFriend(userId,label);} @PostMapping("/{userId}/blocked") public void block(@PathVariable int userId,@RequestBody Map<String,String> b){service.addBlocked(userId,b.get("name"));}}
